+    /// Dequantize any supported tensor type to F32
+    /// Note: Uses intermediate BF16 buffer for quantized types
+    pub fn dequantizeToF32(self: *Self, name: []const u8, dest: []f32) !void {
+        const info = self.getTensor(name) orelse return error.TensorNotFound;
+        const n_elements = info.numElements();
+
+        if (dest.len < n_elements) return error.DestBufferTooSmall;
+
+        // For F32 tensors, copy directly
+        if (info.type_ == .f32) {
+            const src = self.getTensorData(info);
+            const src_f32: []const f32 = @as([*]const f32, @ptrCast(@alignCast(src.ptr)))[0..n_elements];
+            @memcpy(dest[0..n_elements], src_f32);
+            return;
+        }
+
+        // For other types, dequantize to BF16 first, then convert
+        const temp_bf16 = self.allocator.alloc(BF16, n_elements) catch return error.OutOfMemory;
+        defer self.allocator.free(temp_bf16);
+
+        try self.dequantizeToBF16(name, temp_bf16);
+
+        // Convert BF16 to F32
+        for (temp_bf16, 0..) |bf16_val, i| {
+            dest[i] = bf16ToF32(bf16_val);
+        }
+    }
