+    /// Dequantize partial Q4_K tensor to F32 (for testing/debugging)
+    pub fn dequantizePartialQ4K(self: *Self, info: GGUFTensorInfo, dest: []f32, offset: usize, count: usize) !void {
+        const src = self.getTensorData(info);
+
+        // Q4_K uses 256-element blocks
+        const QK_K = 256;
+        const block_start = offset / QK_K;
+        const block_offset = offset % QK_K;
+        const blocks_needed = (block_offset + count + QK_K - 1) / QK_K;
+
+        const blocks: [*]const Q4_K_BLOCK = @as([*]const Q4_K_BLOCK, @ptrCast(@alignCast(src.ptr)));
+
+        var dest_idx: usize = 0;
+        for (0..blocks_needed) |b| {
+            const block = blocks[block_start + b];
+            const d = f16ToF32(block.d);
+            const min = f16ToF32(block.dmin);
+
+            var q_idx: usize = 0;
+            var is: usize = 0;
+
+            // Process in 64-element chunks
+            var j: usize = 0;
+            while (j < QK_K) : (j += 64) {
+                var sc: u8 = undefined;
+                var m: u8 = undefined;
+
+                // First 32 elements
+                getScaleMinK4(is + 0, block.scales, &sc, &m);
+                const d1 = d * @as(f32, @floatFromInt(sc));
+                const m1 = min * @as(f32, @floatFromInt(m));
+
+                // Second 32 elements
+                getScaleMinK4(is + 1, block.scales, &sc, &m);
+                const d2 = d * @as(f32, @floatFromInt(sc));
+                const m2 = min * @as(f32, @floatFromInt(m));
+
+                // Dequantize 32 lower 4-bit values
+                for (0..32) |l| {
+                    const elem_idx = j + l;
+                    if (b == 0 and elem_idx < block_offset) continue;
+                    if (dest_idx >= count) return;
+
+                    const val = d1 * @as(f32, @floatFromInt(block.qs[q_idx + l] & 0xF)) - m1;
+                    dest[dest_idx] = val;
+                    dest_idx += 1;
+                }
+
+                // Dequantize 32 upper 4-bit values
+                for (0..32) |l| {
+                    const elem_idx = j + 32 + l;
+                    if (b == 0 and elem_idx < block_offset) continue;
+                    if (dest_idx >= count) return;
+
+                    const val = d2 * @as(f32, @floatFromInt(block.qs[q_idx + l] >> 4)) - m2;
+                    dest[dest_idx] = val;
+                    dest_idx += 1;
+                }
+
+                q_idx += 32;
+                is += 2;
+            }
+        }
+    }
